async function createSession(
  eventStore: EventStore,
  sessions: Map<string, FabricHttpSession>,
): Promise<FabricHttpSession> {
  const { createFabricServer } = await import('./index.js');
  const server = createFabricServer(); // new McpServer + 4 tool registrations
  const transport = new StreamableHTTPServerTransport({
    sessionIdGenerator: randomUUID,
    enableJsonResponse: true, // disables streaming progress
    eventStore,
    onsessioninitialized: async (sessionId) => {
      sessions.set(sessionId, { server, transport });
    },
    onsessionclosed: async (sessionId) => {
      sessions.delete(sessionId);
    },
  });
  transport.onclose = () => { sessions.delete(transport.sessionId!); };
  await server.connect(transport);
  return { server, transport };
}

export function resolveProjectRoot(): string {
  return process.env.FABRIC_PROJECT_ROOT ?? process.cwd();
}

export function readAgentsMeta(projectRoot: string): AgentsMeta {
  const metaPath = getAgentsMetaPath(projectRoot);
  let raw: string;
  try {
    raw = readFileSync(metaPath, 'utf8'); // synchronous blocking I/O
  } catch (error) {
    if (error?.code === 'ENOENT') throw new AgentsMetaFileMissingError(metaPath);
    throw error;
  }
  return agentsMetaSchema.parse(JSON.parse(raw));
}

export function createEventsHandler(options: CreateEventsHandlerOptions) {
  const { projectRoot } = options;
  const state: EventsState = { clients: new Set(), ... };

  return async function handleEvents(req, res): Promise<void> {
    if (state.clients.size >= CONNECTION_LIMIT) { // hard limit: 10
      res.statusCode = 503; res.end(JSON.stringify({error: ...})); return;
    }
    await ensureWatcher(state, projectRoot); // lazy watcher start
    res.setHeader('Content-Type', 'text/event-stream; charset=utf-8');
    res.write(': connected\n\n'); // initial keepalive
    state.clients.add(res);
    // cleanup on disconnect
    req.on('close', () => void cleanup());
    // NO Last-Event-ID replay here
  };
}

