}

export function parseFabricEvent(raw: string): FabricEvent | null {
  try {
    const parsed = JSON.parse(raw) as Partial<FabricEvent>;
    return typeof parsed.type === 'string' && 'payload' in parsed
      ? (parsed as FabricEvent) : null;
    // Does NOT use fabricEventSchema.safeParse() from shared
  } catch { return null; }
}

export async function getRules(projectRoot: string, input: GetRulesInput): Promise<GetRulesResult> {
  const context = await loadGetRulesContext(projectRoot);
  // loads AgentsMeta (readFileSync), AGENTS.md (readFile), all humanLock entries
  const stale = input.client_hash !== undefined && input.client_hash !== context.meta.revision;
  const rules = await resolveRulesForPath(projectRoot, context, input.path);
  // resolveRulesForPath reads each matched rule file from disk
  try {
    await appendGetRulesAuditEvent(...);
  } catch { /* best-effort */ }
  return { revision_hash: context.meta.revision, stale, rules };
}

